**3. ملف `script.js`**
(يتحكم بقائمة الجوال، احفظه مع الملفين السابقين)

```javascript
// للتعامل مع زر القائمة في الأجهزة الذكية والهواتف
const menuToggle = document.querySelector('.menu-toggle');
const navLinks = document.querySelector('.nav-links');

// عند الضغط على أيقونة الهامبرغر، أظهر أو أخفي القائمة
menuToggle.addEventListener('click', () => {
    navLinks.classList.toggle('active');
});

// عند الضغط على أي رابط داخل القائمة (أثناء تصفح الهاتف)، أغلق القائمة تلقائياً
const links = document.querySelectorAll('.nav-links li a');
links.forEach(link => {
    link.addEventListener('click', () => {
        navLinks.classList.remove('active');
    });
});
```

